function getDaysInMonth() {
  const now = new Date(),
    year = now.getFullYear(),
    month = now.getMonth();
  return {
    firstDay: new Date(year, month, 1).getDay(),
    daysInMonth: new Date(year, month + 1, 0).getDate(),
    today: now.getDate(),
    monthName: now.toLocaleString('default', { month: 'long' }),
    year,
  };
}

