function HeadshotUpload({
  photo,
  onChange,
}: {
  photo: string;
  onChange: (d: string) => void;
}) {
  const ref = useRef<HTMLInputElement>(null);
  const handle = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const r = new FileReader();
    r.onload = (ev) => onChange(ev.target?.result as string);
    r.readAsDataURL(f);
  };
  return (
    <div className="headshot-upload">
      <div className="headshot-preview" onClick={() => ref.current?.click()}>
        {photo ? (
          <img src={photo} alt="hs" />
        ) : (
          <span className="headshot-placeholder">📷</span>
        )}
        <div className="headshot-overlay">✏️</div>
      </div>
      <div className="headshot-hint">
        {photo ? 'Click to change' : 'Upload headshot'}
      </div>
      <input
        ref={ref}
        type="file"
        accept="image/*"
        style={{ display: 'none' }}
        onChange={handle}
      />
    </div>
  );
}

